<?php
$resource=(string)($data['resource']??'Records'); $columns=isset($data['columns'])&&is_array($data['columns'])?$data['columns']:['Name','Status','Updated']; $rows=isset($data['rows'])&&is_array($data['rows'])?$data['rows']:[];
?>
<div class="admin-heading"><div><p class="eyebrow">Administration</p><h1 class="heading-admin"><?= $esc($resource) ?></h1><p class="muted"><?= $esc((string)($data['description']??'Manage authorized records. Every change is written to the audit log.')) ?></p></div><?php if(!empty($data['create_url'])): ?><a class="button button-gold" href="<?= $esc($data['create_url']) ?>">Create new</a><?php endif; ?></div>
<section class="card card-pad"><form class="toolbar-inner" method="get" role="search"><label class="search-control"><span class="sr-only">Search <?= $esc($resource) ?></span><input type="search" name="q" value="<?= $esc((string)($data['query']??'')) ?>" placeholder="Search <?= $esc(mb_strtolower($resource)) ?>…"></label><div class="filter-row"><label><span class="sr-only">Filter status</span><select name="status"><option value="">All statuses</option><option>Active</option><option>Disabled</option><option>Pending</option></select></label><button class="button button-ghost">Filter</button></div></form></section>
